const items = $input.all();
const results = [];

for (const item of items) {
    let extractedText = "";
    const sheets = item.json.sheets || [];

    sheets.forEach(sheet => {
        const sheetTitle = sheet.properties?.title || "Untitled Sheet";
        extractedText += `### Sheet: ${sheetTitle}\n`;

        const rowData = sheet.data?.[0]?.rowData || [];

        rowData.forEach(row => {
            const rowValues = row.values || [];
            const rowString = rowValues
                .map(cell => cell.formattedValue || cell.effectiveValue?.stringValue || "")
                .join(" | ");

            if (rowString.trim().replace(/\|/g, "") !== "") {
                extractedText += `| ${rowString} |\n`;
            }
        });
        extractedText += "\n";
    });

    results.push({
        json: {
            spreadsheetTitle: item.json.properties?.title,
            cleanText: extractedText.trim()
        }
    });
}

return results;

const items = $input.all();
let extractedText = "### Sheet: XLSX Data\n";

if (items.length > 0) {
    // Extract headers from the first row's keys
    const headers = Object.keys(items[0].json);
    extractedText += `| ${headers.join(" | ")} |\n`;

    // Process rows
    items.forEach(item => {
        const rowValues = headers.map(header => {
            const val = item.json[header];
            return (val !== null && val !== undefined) ? val : "";
        });
        const rowString = rowValues.join(" | ");

        if (rowString.trim() !== "") {
            extractedText += `| ${rowString} |\n`;
        }
    });
}

return [{
    json: {
        spreadsheetTitle: "XLSX Attachment",
        cleanText: extractedText.trim()
    }
}];

const items = $input.all();
const results = [];

for (const item of items) {
    let outputText = "";
    const slides = item.json.slides || [];

    slides.forEach((slide, index) => {
        let slideText = `--- Slide ${index + 1} ---\n`;
        let hasContent = false;

        const elements = slide.pageElements || [];
        elements.forEach(element => {
            if (element.shape && element.shape.text && element.shape.text.textElements) {
                element.shape.text.textElements.forEach(te => {
                    if (te.textRun && te.textRun.content) {
                        const content = te.textRun.content.trim();
                        if (content !== "") {
                            slideText += content + "\n";
                            hasContent = true;
                        }
                    }
                });
            }
        });

        if (hasContent) {
            outputText += slideText + "\n";
        }
    });

    results.push({
        json: {
            presentationId: item.json.presentationId || "unknown",
            formattedContent: outputText.trim()
        }
    });
}

return results;

const items = $input.all();
const results = [];

const parseElements = (elements) => {
  return elements
    .map(el => el.textRun?.content || "")
    .join("");
};

const parseContent = (contentArray) => {
  let text = "";
  for (const item of contentArray) {
    if (item.paragraph) {
      text += parseElements(item.paragraph.elements);
    } else if (item.table) {
      for (const row of item.table.tableRows) {
        for (const cell of row.tableCells) {
          text += parseContent(cell.content || []) + " | ";
        }
        text += "\n";
      }
    }
  }
  return text;
};

for (const item of items) {
  const bodyContent = item.json.body?.content || [];
  const cleanText = parseContent(bodyContent);

  results.push({
    json: {
      title: item.json.title,
      documentId: item.json.documentId,
      text: cleanText.replace(/\r\n/g, "\n").trim()
    }
  });
}

return results;
